import{_ as a,o as n,c as i,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse(`{"title":"2. Commencement And Transitional","description":"","frontmatter":{"title":"2. Commencement And Transitional","eba":"Children's Services Award 2010","topics":["leave","public-holidays","hours","shift-work","wages","employment","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/application-operation/2-commencement-and-transitional.md","filePath":"ebas/childrens-services/application-operation/2-commencement-and-transitional.md"}`),r={name:"ebas/childrens-services/application-operation/2-commencement-and-transitional.md"};function o(s,e,l,m,p,d){return n(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="_2-commencement-and-transitional" tabindex="-1">2. Commencement And Transitional <a class="header-anchor" href="#_2-commencement-and-transitional" aria-label="Permalink to &quot;2. Commencement And Transitional&quot;">​</a></h1><ol><li><p>This award commences on 1 January 2010.</p></li><li><p>The monetary obligations imposed on employers by this award may be absorbed into overaward payments. Nothing in this award requires an employer to maintain or increase any overaward payment.</p></li><li><p>This award contains transitional arrangements which specify when particular parts of the award come into effect. Some of the transitional arrangements are in clauses in the main part of the award. There are also transitional arrangements in <a href="/eba/ebas/childrens-services/schedules/a-transitional-provisions.html">Schedule A</a>. The arrangements in <a href="/eba/ebas/childrens-services/schedules/a-transitional-provisions.html">Schedule A</a> deal with:</p></li><li><p>minimum wages and piecework rates</p></li><li><p>casual or part-time loadings</p></li><li><p>Saturday, Sunday, public holiday, evening or other penalties</p></li><li><p>shift allowances/penalties.</p></li><li><p>Neither the making of this award nor the operation of any transitional arrangements is intended to result in a reduction in the take-home pay of employees covered by the award. On application by or on behalf of an employee who suffers a reduction in take-home pay as a result of the making of this award or the operation of any transitional arrangements, the Fair Work Commission may make any order it considers appropriate to remedy the situation.</p></li><li><p>The Fair Work Commission may review the transitional arrangements in this award and make a determination varying the award.</p></li><li><p>The Fair Work Commission may review the transitional arrangements:</p><p>a. on its own initiative; or</p><p>b. on application by an employer, employee, organisation or outworker entity covered by the modern award; or</p><p>c. on application by an organisation that is entitled to represent the industrial interests of one or more employers or employees that are covered by the modern award; or</p><p>d. in relation to outworker arrangements, on application by an organisation that is entitled to represent the industrial interests of one or more outworkers to whom the arrangements relate.</p></li></ol><p>Plain language terms: start date, transition.</p>',3)])])}const y=a(r,[["render",o]]);export{h as __pageData,y as default};
